+    ProvisioningRecipe::new(
+        RecipeId::new("intercom.bearer_token"),
+        "1",
+        "Provision Intercom connector with an OAuth2 access token",
+    )
+    .with_step(ProvisioningStep::new(
+        StepId::new("obtain_token"),
